1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Scenario = {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Array<{ op: "quote"; items: Array<{ type: string }> }>;
15	};
16	
17	type QuoteResult = { premium: number };
18	
19	const basePremiumFor = (items: Array<{ type: string }>): number =>
20	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
21	
22	const quotePremium = (items: Array<{ type: string }>): QuoteResult => {
23	  const base = basePremiumFor(items);
24	  return { premium: base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE };
25	};
26	
27	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
28	  const results = scenario.steps.map((step) => quotePremium(step.items));
29	  return { results };
30	};
